#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int check_win(int *A, int N, int Z1, int Z2, int S, int turn) {
    if (S == Z1 || S == Z2) return turn;
    if (turn > 10000000000) return 0;
    int min = 10000000000;
    for (int i = 0; i < N; i++) {
        int temp = check_win(A, N, Z1, Z2, S + A[i], turn + 1);
        if (temp == 1) return 1;
        if (temp == 0 && turn % 2 == 1) min = 0;
        temp = check_win(A, N, Z1, Z2, S - A[i], turn + 1);
        if (temp == 1) return 1;
        if (temp == 0 && turn % 2 == 1) min = 0;
    }
    if (min == 10000000000) return 2;
    return min;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, Z1, Z2;
        scanf("%d %d %d", &N, &Z1, &Z2);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        int result = check_win(A, N, Z1, Z2, 0, 0);
        printf("%d\n", result);
        free(A);
    }
    return 0;
}

